import {
  createAccountSearchConfig as createBase,
  preloadAccountCatalogLookup as preloadBase,
  clearAccountSearchCache,
  type CreateAccountSearchConfigOptions,
  type AccountSearchMode,
} from '@linm-soft-org/linm-web-common-components';
import { erpFinanceAccountSearchApi } from './accountSearchApi';

export type { AccountSearchMode, CreateAccountSearchConfigOptions };

export function createAccountSearchConfig(
  options: CreateAccountSearchConfigOptions = {},
) {
  return createBase(erpFinanceAccountSearchApi, options);
}

export function preloadAccountCatalogLookup(): void {
  preloadBase(erpFinanceAccountSearchApi);
}

export { clearAccountSearchCache };

if (typeof window !== 'undefined') {
  window.addEventListener('linm:company:changed', () => {
    clearAccountSearchCache();
  });
}

void preloadAccountCatalogLookup();
